const input = $json;
let raw = '';

if (input.candidates?.[0]?.content?.parts?.[0]?.text) {
  raw = input.candidates[0].content.parts[0].text;
} else if (input.text) {
  raw = input.text;
} else if (input.output) {
  raw = input.output;
} else {
  raw = JSON.stringify(input);
}

const cleaned = String(raw)
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let data;
try {
  data = JSON.parse(cleaned);
} catch (error) {
  throw new Error('AI output is not valid JSON: ' + error.message + '\nRaw output:\n' + cleaned);
}

return [{
  json: {
    user_question: $('Set User Question and Support Prompt').item.json.user_question,
    client_email: $('Set User Question and Support Prompt').item.json.client_email,
    support_email: $('Set User Question and Support Prompt').item.json.support_email,
    answer: data.answer || '',
    source_based: data.source_based || 'No',
    missing_information: data.missing_information || '',
    recommended_next_step: data.recommended_next_step || '',
    handoff_required: data.handoff_required || 'No',
    handoff_reason: data.handoff_reason || '',
    support_summary: data.support_summary || '',
    created_at: new Date().toISOString()
  }
}];

